import pytest

# Replace `your_module` with the module where remove_duplicates is defined
from your_module import remove_duplicates


def test_remove_duplicates_happy_path_preserves_order():
    assert remove_duplicates([1, 2, 1, 3, 2, 4]) == [1, 2, 3, 4]


def test_remove_duplicates_strings():
    assert remove_duplicates(["a", "b", "a", "c", "b"]) == ["a", "b", "c"]


def test_remove_duplicates_no_duplicates():
    original = [1, 2, 3]
    assert remove_duplicates(original) == [1, 2, 3]


def test_remove_duplicates_empty_list():
    assert remove_duplicates([]) == []


def test_remove_duplicates_all_duplicates():
    assert remove_duplicates([5, 5, 5, 5]) == [5]


def test_remove_duplicates_mixed_hashable_types():
    assert remove_duplicates([1, "1", 1, None, "1", None]) == [1, "1", None]


def test_remove_duplicates_preserves_first_occurrence():
    assert remove_duplicates(["x", "y", "x", "z", "y"]) == ["x", "y", "z"]


def test_remove_duplicates_does_not_modify_original_list():
    original = [1, 2, 1, 3]
    result = remove_duplicates(original)

    assert result == [1, 2, 3]
    assert original == [1, 2, 1, 3]


def test_remove_duplicates_with_tuple_items():
    assert remove_duplicates([(1, 2), (3, 4), (1, 2)]) == [(1, 2), (3, 4)]


def test_remove_duplicates_bool_and_int_equality_edge_case():
    # In Python, True == 1 and False == 0
    assert remove_duplicates([1, True, 0, False]) == [1, 0]


def test_remove_duplicates_raises_type_error_for_unhashable_list_item():
    with pytest.raises(TypeError):
        remove_duplicates([[1], [1]])


